// gunsfx.js — owner-supplied gunshot + dry-fire SFX, appended to the SFX pack
// from soundfx.js (like carsfx.js). Loaded AFTER soundfx.js and BEFORE game.js.
// Data-URL WAVs; file:// safe, no external refs. game.js maps these via SFX_MAP:
//   pistol   -> pistol AND smg shots      rifle -> rifle shot
//   ak47     -> AK-47 (auto) shot         gunempty -> empty-mag dry click
if (typeof SFX_PACK !== "undefined") {
  SFX_PACK.pistol = ["data:audio/wav;base64,"];
  SFX_PACK.rifle = ["data:audio/wav;base64,"];
  SFX_PACK.ak47 = ["data:audio/wav;base64,"];
  SFX_PACK.gunempty = ["data:audio/wav;base64,"];
}
